package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSetWhenNullStringIsNull() {
        // Use DEFAULT instance where nullString is null
        CSVFormat format = CSVFormat.DEFAULT;
        // isNullStringSet should return false
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSetWhenNullStringIsNotNull() throws Exception {
        // Create a CSVFormat with non-null nullString using withNullString method
        CSVFormat format = CSVFormat.DEFAULT;

        CSVFormat newFormat;
        try {
            newFormat = format.withNullString("NULL");
        } catch (NoSuchMethodError e) {
            // fallback to reflection clone
            Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
            nullStringField.setAccessible(true);

            // create a new instance by copying all fields from format and setting nullString to "NULL"
            // Since CSVFormat is final and has no public constructor, we clone via reflection
            // but here we just modify a copy of DEFAULT via reflection

            // clone via serialization or reflection is complex, so we create a new instance via withNullString if possible
            // if not possible, we modify the existing instance (not recommended but fallback)
            newFormat = format;
            nullStringField.set(newFormat, "NULL");
        }

        // isNullStringSet should return true
        assertTrue(newFormat.isNullStringSet());
    }
}
